// 处理进度追踪请求
const input = $input.first().json;

const trackingData = {
  userId: input.userId || 'anonymous',
  pathId: input.pathId || 'default',
  action: input.action || 'update',
  itemType: input.itemType || 'topic',
  itemId: input.itemId || 'item_' + Date.now(),
  timestamp: new Date().toISOString(),
  metadata: input.metadata || {}
};

return {
  json: {
    trackingData,
    processedAt: new Date().toISOString()
  }
};

// 简化的进度计算
const trackingData = $input.first().json.json.trackingData;

// 模拟进度数据
const progress = {
  overall: Math.floor(Math.random() * 30) + 20, // 20-50%
  completedItems: Math.floor(Math.random() * 10) + 5,
  totalItems: 40,
  currentStreak: Math.floor(Math.random() * 7) + 1
};

// 生成激励消息
const messages = [
  "🌱 开始你的学习之旅吧！",
  "💪 不错的开始，继续保持！",
  "🎯 已经过半了，加油！",
  "🔥 胜利在望，冲刺！",
  "🏆 恭喜完成！你是最棒的！"
];

const messageIndex = Math.min(Math.floor(progress.overall / 20), messages.length - 1);

return {
  json: {
    status: 'success',
    progress: progress,
    statistics: {
      startDate: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString(),
      totalDays: 30,
      averagePerWeek: 5,
      estimatedCompletionDate: new Date(Date.now() + 60 * 24 * 60 * 60 * 1000).toISOString()
    },
    achievements: [
      { id: 'first_step', name: '第一步', unlocked: true },
      { id: 'quarter_way', name: '四分之一', unlocked: progress.overall >= 25 },
      { id: 'halfway', name: '半途', unlocked: progress.overall >= 50 }
    ],
    motivation: messages[messageIndex],
    streak: progress.currentStreak,
    trackingData: trackingData
  }
};
